import pandas as pdOHLC_COLUMNS = ["Open", "High", "Low", "Close", "Volume"]def empty_ohlc_dataframe():    """    Return an empty OHLC DataFrame with the expected columns.    This keeps the rest of the application safe if the API fails.    """    return pd.DataFrame(columns=OHLC_COLUMNS)def build_ohlc_dataframe(raw_data):    """    Convert raw CoinGecko OHLC API data into a Pandas DataFrame.    CoinGecko returns data in this format:    [        [timestamp, open, high, low, close],        ...    ]    """    if not raw_data:        return empty_ohlc_dataframe()    df = pd.DataFrame(        raw_data,        columns=["timestamp", "Open", "High", "Low", "Close"]    )    df["timestamp"] = pd.to_datetime(df["timestamp"], unit="ms")    df.set_index("timestamp", inplace=True)    for column in ["Open", "High", "Low", "Close"]:        df[column] = pd.to_numeric(df[column], errors="coerce")    df.dropna(subset=["Open", "High", "Low", "Close"], inplace=True)    # CoinGecko OHLC endpoint does not provide volume.    # mplfinance expects this column, so we add it as a placeholder.    df["Volume"] = 0    return df 